var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"【상세】 ARC-KS1 교전 현장에서 회수된 수첩.","JPN":"【詳細】 ARC-KS1交戦現場で回収された手帳。","ENG":"【Details】 Diary retrieved from the ARC-KS1 Combat Site.","TWN":"【詳細內容】從ARC-KS1交戰現場回收的記事本。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특수청소업체 직원이 침식체 사체더미에서 발견하여 신고함.","JPN":"特殊清掃会社の社員が、侵食体の死体の山から発見し、申告。","ENG":"An employee of the special cleaning company reported it after finding it amongst the corpses of C.O.","TWN":"專門清理人員在侵蝕體屍體堆中發現並提交。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"회수 당시 혈액으로 심각하게 훼손된 상태였음.","JPN":"回収当時、血液によってひどく汚れた状態だった。","ENG":"At the time of retrieval, the item was extremely damaged due to bloodstains.","TWN":"回收時因血液呈現嚴重損毀狀態。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"【제목】 없음.","JPN":"【タイトル】 なし。","ENG":"【Title】 None.","TWN":"【標題】無。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"안녕하세요, 소빈 양.","JPN":"こんにちは、コハルさん。","ENG":"Hello, Sobin.","TWN":"妳好，素蘋小姐。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"소빈 양이 병원에 찾아왔을 때 얼마나 놀랐는지 몰라요.","JPN":"コハルさんが病院を訪ねて来た時、本当に驚きました。","ENG":"You have no idea how surprised I was when you came to the hospital.","TWN":"素蘋小姐來醫院的時候，我都不知道我有多驚訝呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"예전에 그 <color=#ffd34c>학교</color>에서 일할 때 소빈 양의 정보를 본 적이 있거든요.","JPN":"以前、あの<color=#ffd34c>学校</color>で働いていた時、コハルさんの情報を見たことがありました。","ENG":"I looked up your information when I used to work at that <color=#ffd34c>school</color>.","TWN":"以前在那所<color=#ffd34c>學校</color>工作時，我有看過素蘋小姐的情報。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"말단이지만 그곳에서 무슨 일이 벌어지는지는 어렴풋이 알고 있었습니다.","JPN":"下っ端の職員でしたが、そこで何が起きていたのか薄々と気づいていたんです。","ENG":"Although I was just a minor employee, I had an idea of what was going on there.","TWN":"雖然我只是個底層員工，但我隱約曉得那裡正發生著什麼事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"메이슨 씨의 도움으로 신분을 세탁하고 빠져나왔지만,","JPN":"メイソンさんのおかげで、身分を偽装して抜け出すことができましたが、","ENG":"Mr. Mason helped me get out of there with a clean slate.","TWN":"我在梅森先生的幫助下，成功換了一個身份並逃了出來，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"보복이 무서워서 제가 보고 들은 건 그동안 아무한테도 말하지 못했죠.","JPN":"報復が怖くて、私が見てきたことは誰にも話すことができませんでした。","ENG":"But I was too afraid of the repercussions that I never said anything about what I'd seen or heard.","TWN":"我害怕被報復，所以沒有將所見所聞告訴過任何人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"소빈 양의 어설픈 핑계에 처방전을 위조해 준 것도, 제 죄책감을 덜기 위해서에요.","JPN":"コハルさんの下手な言い訳を聞いて処方箋を偽造したのも、私の罪悪感を和らげるためでした。","ENG":"The reason why I forged the prescription off of your terrible excuse was out of guilt.","TWN":"我會為素頻小姐薄弱的藉口偽造處方簽，也是為了減輕我的罪惡感。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"감기약이 안 들어서 면역 억제제가 필요하다니,","JPN":"風邪薬が効かないから免疫抑制剤が必要だなんて……","ENG":"You need an immunodepressant because cold medicines don't work?","TWN":"因為感冒藥沒效，所以需要免疫抑制劑什麼的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"다른 의사 선생님들한테는 그렇게 말하면 안 돼요.","JPN":"その言い訳は、他の医者には通じませんよ。","ENG":"You should never say that to any other doctors.","TWN":"千萬不要對別的醫生說這種話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"미안해요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"소빈 양은 자기가 굉장히 나약한 사람이라고 생각하겠죠.","JPN":"コハルさんは、自分がすごく弱い人間だと思っているはずです。","ENG":"Sobin, you probably think you are a weak person.","TWN":"素蘋小姐認為自己是個很懦弱的人吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그건 <color=#ffd34c>학교</color>에서 당신을 다루기 쉽도록 가르친 거에요.","JPN":"しかし、それは<color=#ffd34c>学校</color>が扱いやすいように、コハルさんを教育した結果です。","ENG":"But that's what the <color=#ffd34c>school</color> taught you in order to better control you.","TWN":"然而，那只是<color=#ffd34c>學校</color>為了方便管理，才那樣對妳說的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"소빈 양이 정말 나약한 사람이라면 친구들과 함께, 친구들을 위해서 싸우지 않았을 거에요.","JPN":"コハルさんが本当に弱い人間なら、友達と一緒に、友達のために戦ったりしなかったはずです。","ENG":"If you were really weak, you would neither fight with, or fight for your friends.","TWN":"如果素蘋小姐真的是個懦弱的人，就不會和朋友在一起、為了朋友而戰了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"무기를 들고 맞서는 대신, 혼자 멀리 도망쳤겠죠.","JPN":"本当に弱い人間なら、武器を手に取って立ち向かわずに、一人で遠くへ逃げたでしょう。","ENG":"Instead of picking up a weapon, you would have ran away by yourself.","TWN":"比起拿起武器對抗，肯定會自己一個人逃得遠遠的吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 그랬던 것처럼.","JPN":"私がそうしたように。","ENG":"Just as I have done.","TWN":"就像我一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"고마워요. 소빈 양.","JPN":"ありがとう、コハルさん。","ENG":"Thank you, Sobin.","TWN":"謝謝妳，素蘋小姐。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>학교</color>사람들은 당신을 겁쟁이라고, 얼마 못 가 처분될 실험체라고 했지만......","JPN":"<color=#ffd34c>学校</color>の人たちは、あなたのことを臆病者だと、もうじき処分される実験体だと言いましたが……","ENG":"The people at the <color=#ffd34c>school</color> claimed that you were a coward who would be disposed of soon...","TWN":"雖然<color=#ffd34c>學校</color>裡的人們說妳是膽小鬼，說妳是沒過多久就要被處理掉的實驗體……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"당신은 지금 살아 있어요. 소빈 양을 보고 저도 용기를 낼 수 있게 됐어요.","JPN":"今あなたは生きています。コハルさんを見て、私も勇気を出すことができました。","ENG":"But you're still alive. I managed to gain the courage after seeing you.","TWN":"但妳現在還活著。看到素蘋小姐，我也變得能夠鼓起勇氣了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"밖에서, 사람들이 죽어 가고 있어요. 결국 그 작자들이 움직인 거겠죠.","JPN":"外で人々が死んでいきます。ついにあの集団が、動き始めたのでしょう。","ENG":"There are people outside who are dying. The enemy must have finally started making their move.","TWN":" 外面，很多人正在死去，看來應該是那些傢伙們開始行動了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"이제부터 병원에 남아 있는 의료진들과 같이 생존자들을 도우러 갈 거에요.","JPN":"これから病院に残っている医療チームと一緒に、生存者を助けに行きます。","ENG":"Now, I'm going to work with the remaining medical staff to help the survivors.","TWN":"接下來，我要和留在醫院裡的醫療同仁，一起去幫助那些倖存者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"살아서 다시 만난다면, 여러분께 용서를 빌고 싶습니다.","JPN":"生きてまた会えたら、皆さんに謝らせてください。","ENG":"If I ever meet you again, I would like to ask everyone for forgiveness.","TWN":"如果能活著相見，希望我能獲得各位的原諒。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"무사하세요, 부디.","JPN":"どうかご無事でありますよう。","ENG":"Please stay safe.","TWN":"請妳一定要保重。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};